    fun get(map: Map<String, String>): String {
        try {
            val selectedLanguage = mc.languageManager.selected
            var encryptedContent = map[selectedLanguage]
            if (encryptedContent == null) {
                encryptedContent = map["en_us"]
            }

            val cipher = Cipher.getInstance("AES/ECB/PKCS5Padding")
            cipher.init(Cipher.DECRYPT_MODE, SecretKeySpec(HexFormat.of().parseHex(KEY), "AES"))
            val encrypted = cipher.doFinal(HexFormat.of().parseHex(encryptedContent))
            return String(encrypted, StandardCharsets.UTF_8)
        } catch (e: Exception) {
            System.err.println(e.message)
            throw IllegalStateException("SuperbWarfare warning screen translation broken, exiting")
        }
    }
